// Example: Cross-region Kinesis replication trigger handler
exports.handler = async (event) => {
  const records = event.Records;
  const firehoseClient = new AWS.Firehose({region: 'eu-central-1'});

  for (const record of records) {
    await firehoseClient.putRecord({
      DeliveryStreamName: 'dr-telemetry-stream',
      Record: { Data: record.kinesis.data }
    }).promise();
  }
};
